+    #[test]
+    fn outlier_detection() {
+        // Normal values with one extreme outlier.
+        let mut sorted: Vec<u64> = (1..=99).collect();
+        sorted.push(1000); // Outlier.
+        sorted.sort_unstable();
+
+        let outliers = count_outliers(&sorted);
+        assert!(outliers >= 1);
+    }
